actions.script:
// Aggressively sanitize context to remove Path/FileItem objects that cause StackOverflow
List keysToRemove = []
context.each { k, v ->
    if (k == 'jsonFile' || k == 'schemaFile' || v instanceof java.nio.file.Path || v instanceof File || (v != null && v.class.name.contains('FileItem'))) {
        keysToRemove.add(k)
    }
}
keysToRemove.each { context.remove(it) }
// Also try to remove from web parameters if accessible
if (ec.web.parameters.containsKey('jsonFile')) ec.web.parameters.remove('jsonFile')
if (ec.web.parameters.containsKey('schemaFile')) ec.web.parameters.remove('schemaFile')

if (context.resultList) {
    ec.web.session.setAttribute("wizardResultList", context.resultList)
    ec.web.session.setAttribute("wizardJsonSchemaString", context.jsonSchemaString)
} else if (context.fieldList) {
    ec.web.session.setAttribute("wizardResultList", context.fieldList)
    context.resultList = context.fieldList 
}

List wList = ec.web.session.getAttribute("wizardResultList")
if (wList != null && itemIndex) {
    int idx = itemIndex as int
    if (idx >= 0 && idx < wList.size()) {
        wList.remove(idx)
    }
    ec.web.session.setAttribute("wizardResultList", wList)
}

// Clear session data after successful save
ec.web.session.removeAttribute("wizardResultList")
ec.web.session.removeAttribute("wizardJsonSchemaString")

pre-actions.script:
// 1. Handling edit mode via filename parameter
def currentSessionSchema = ec.web.session.getAttribute("wizardSchemaName")

// Force reload if we have a filename and (it's new OR we don't have a list yet)
// AND ensure we don't reload if we are just submitting the form (wizardStep 2)
// Actually, if we are editing, we are always jumping to step 2. 
// The issue is distinguishing between "Initial Load of File" and "Post-back of Form".
// If request parameter 'filename' is present, it's likely the link from Browse.
// But if we submit the form, do we keep 'filename'? 
// The form transition "saveRefinedSchema" likely redirects or we stay on page?
// "saveRefinedSchema" redirects to Browse.
// "addFieldToWizard" redirects to "." with parameter wizardStep=2.

// So if 'filename' is in parameters, it MUST be an initial load/switch.
// Because addField/removeField don't pass 'filename'.

if (filename) {
    // Purge cache first to ensure fresh load
    ec.web.session.removeAttribute("wizardResultList")
    ec.web.session.removeAttribute("wizardSchemaName")

    // If it's a new file or we just arrived, reload.
    def result = ec.service.sync().name("JsonSchemaServices.flatten#JsonSchema")
        .parameter("schemaFileName", filename)
        .call()

    if (result.fieldList) {
        ec.web.session.setAttribute("wizardResultList", result.fieldList)
        ec.web.session.setAttribute("wizardSchemaName", filename) 
        context.resultList = result.fieldList
        context.wizardStep = '2' 
        context.schemaName = filename 
    }
}

// 2. Clear checks
// Clear session data if we are explicitly starting fresh (step 1)
// or if no step is defined (initial load) AND we are not editing
if ((!wizardStep || wizardStep == '1') && !filename) {
     ec.web.session.removeAttribute("wizardResultList")
     ec.web.session.removeAttribute("wizardJsonSchemaString")
     ec.web.session.removeAttribute("wizardSchemaName")
} else {
    // Otherwise load if exists
    if (ec.web.session.getAttribute("wizardResultList")) {
        context.resultList = ec.web.session.getAttribute("wizardResultList")
    }
    if (ec.web.session.getAttribute("wizardJsonSchemaString")) {
        context.jsonSchemaString = ec.web.session.getAttribute("wizardJsonSchemaString")
    }
    // Also ensure schemaName is set if we are editing
    if (ec.web.session.getAttribute("wizardSchemaName")) {
         context.schemaName = ec.web.session.getAttribute("wizardSchemaName")
    }

    // If we jumped to step 2 via edit, explicitly set it
    if (filename && context.resultList) {
        context.wizardStep = '2'
    }
    ec.logger.info("JsonSchemaWizard Pre-Actions: schemaName=[${context.schemaName}] filename=[${filename}]")
}
